350→/// Map MIME type to a file extension.
351→fn extension_for_mime(mime: &str) -> &'static str {
352→    match mime {
353→        "image/png" => "png",
354→        "image/jpeg" | "image/jpg" => "jpg",
355→        "image/gif" => "gif",
356→        "image/webp" => "webp",
357→        "audio/ogg" => "ogg",
358→        "audio/mpeg" | "audio/mp3" => "mp3",
359→        "video/mp4" => "mp4",
360→        "application/pdf" => "pdf",
361→        _ => "bin",
362→    }
363→}
